const aggregated = $(' Aggregate TinyFish Scout Results').first().json;
const gptResponse = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';

let synthesis;
try {
  const cleaned = gptResponse.replace(/```json\n?|```/g, '').trim();
  synthesis = JSON.parse(cleaned);
} catch(e) {
  synthesis = {
    primary_themes: ['Research', 'Analysis', 'Discovery'],
    discovery_summary: `Synthesized ${aggregated.total_deduplicated} papers across ${aggregated.sources_searched.join(', ')}.`,
    recommended_action: 'Review the top-cited papers for key insights.',
    confidence: 0.75,
    trend: 'established',
    top_paper_indices: [0, 1, 2]
  };
}

const topPapers = (synthesis.top_paper_indices || [0,1,2])
  .filter(i => i < aggregated.papers.length)
  .map(i => aggregated.papers[i]);

const researchProfile = {
  research_context: {
    topic: aggregated.query,
    sources: aggregated.sources_searched,
    intent: aggregated.intent_analysis?.intent_label || 'Discovery',
    session_id: aggregated.sessionId,
    timestamp: aggregated.timestamp
  },
  discovery_summary: {
    yield: aggregated.total_deduplicated,
    raw_collected: aggregated.total_raw,
    source_breakdown: aggregated.source_counts,
    scout_statuses: aggregated.scout_statuses,
    primary_themes: synthesis.primary_themes || [],
    confidence: synthesis.confidence || 0.8,
    trend: synthesis.trend || 'established',
    summary: synthesis.discovery_summary || '',
    key_breakthroughs: synthesis.key_breakthroughs || [],
    research_gaps: synthesis.research_gaps || []
  },
  papers_discovered: aggregated.papers.map(p => ({
    title: p.title,
    source: p.source,
    url: p.url,
    published: p.published,
    authors: p.authors,
    citation_count: p.citationCount,
    abstract_excerpt: (p.abstract || '').substring(0, 200),
    evidence: (p.abstract || 'See source URL').substring(0, 150),
    doi: p.doi
  })),
  top_recommendations: topPapers.map(p => ({
    title: p.title,
    url: p.url,
    source: p.source,
    citations: p.citationCount,
    published: p.published
  })),
  recommended_action: synthesis.recommended_action || 'Review the top papers.',
  metadata: {
    keywords_used: aggregated.intent_analysis?.primary_keywords || [],
    tinyfish_verified: true,
    agent_powered: true
  }
};

return [{ json: researchProfile }];
